module fsm(
    input IN,
    input CLK,
    input RST,
    output reg MATCH
);

reg [2:0] state, next_state;
parameter S0 = 3'b000, S1 = 3'b001, S2 = 3'b010, S3 = 3'b011, S4 = 3'b100;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        state <= S0;
        MATCH <= 1'b0;
    end
    else begin
        state <= next_state;
        MATCH <= (next_state == S4) ? 1'b1 : 1'b0;
    end
end

always @(*) begin
    case (state)
        S0: begin
            if (IN) next_state = S1;
            else next_state = S0;
        end
        S1: begin
            if (IN) next_state = S1;
            else next_state = S2;
        end
        S2: begin
            if (IN) next_state = S1;
            else next_state = S3;
        end
        S3: begin
            if (IN) next_state = S4;
            else next_state = S0;
        end
        S4: begin
            if (IN) next_state = S1;
            else next_state = S0;
        end
        default: next_state = S0;
    endcase
end

endmodule
